diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..a8a45ae5ad9a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1402,6 +1402,22 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       return BinaryOperator::CreateAnd(NewAdd, Mask);
     }

+    // (and X, C) + (and Y, C) >>u K where C = 2^K - 1
+    // This computes whether both X and Y have all bits in the mask C set.
+    // Transform to: (and (and X, C), Y)
+    const APInt *AndC1, *AndC2;
+    if (match(Op0, m_OneUse(m_c_Add(m_And(m_Value(X), m_APInt(AndC1)),
+                                      m_And(m_Value(Y), m_APInt(AndC2)))))) {
+      // Check that both ands have the same mask and it's of the form 2^K - 1
+      if (*AndC1 == *AndC2 && (*AndC1 + 1).isPowerOf2()) {
+        unsigned K = (*AndC1 + 1).logBase2();
+        if (K == ShAmtC) {
+          return BinaryOperator::CreateAnd(Builder.CreateAnd(X, ConstantInt::get(Ty, *AndC1)), Y);
+        }
+      }
+    }
+
+
     if (match(Op0, m_OneUse(m_ZExt(m_Value(X)))) &&
         (!Ty->isIntegerTy() || shouldChangeType(Ty, X->getType()))) {
       assert(ShAmtC < X->getType()->getScalarSizeInBits() &&
@@ -1551,15 +1567,16 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
     }

     // Reduce add-carry of bools to logic:
-    // ((zext BoolX) + (zext BoolY)) >> 1 --> zext (BoolX && BoolY)
+    // ((zext BoolX) + (zext BoolY)) >> 1 --> and (zext BoolX), (zext BoolY)
     Value *BoolX, *BoolY;
     if (ShAmtC == 1 && match(Op0, m_Add(m_Value(X), m_Value(Y))) &&
         match(X, m_ZExt(m_Value(BoolX))) && match(Y, m_ZExt(m_Value(BoolY))) &&
         BoolX->getType()->isIntOrIntVectorTy(1) &&
         BoolY->getType()->isIntOrIntVectorTy(1) &&
         (X->hasOneUse() || Y->hasOneUse() || Op0->hasOneUse())) {
-      Value *And = Builder.CreateAnd(BoolX, BoolY);
-      return new ZExtInst(And, Ty);
+      Value *ZextX = Builder.CreateZExt(BoolX, Ty);
+      Value *ZextY = Builder.CreateZExt(BoolY, Ty);
+      return BinaryOperator::CreateAnd(ZextX, ZextY);
     }
   }

